from math import gcd
from typing import List

class Solution:
    def subarrayGCD(self, nums: List[int], k: int) -> int:
        count = 0
        for i in range(len(nums)):
            curr_gcd = nums[i]
            for j in range(i, len(nums)):
                curr_gcd = gcd(curr_gcd, nums[j])
                if curr_gcd == k:
                    count += 1
                elif curr_gcd < k:
                    break
        return count
